The AI responds correctly with meal content, but `formatPlanSummary` only outputs metadata (period type, dates, meal count, cost) — it discards all the actual meal details. The fix is to rewrite `formatPlanSummary` to include recipe names, macros, and ingredients per meal.

Here's what I'd change in `chat_service.go` `formatPlanSummary`:

```go
func formatPlanSummary(result GeneratePlanResult) string {
    proposal := result.Proposal
    plan := proposal.Plan
    var b strings.Builder

    if result.FallbackActive {
        b.WriteString("Fallback mode active — using seeded data instead of AI.\n")
    }

    b.WriteString(fmt.Sprintf("%s plan: %s → %s\n", plan.PeriodType, plan.StartDate, plan.EndDate))

    for _, day := range proposal.Days {
        b.WriteString(fmt.Sprintf("\n%s:\n", day.Date))
        sections := map[string]*dto.PlanMealResponse{
            "Breakfast": day.Sections.Breakfast,
            "Lunch":     day.Sections.Lunch,
            "Dinner":    day.Sections.Dinner,
            "Snacks":    day.Sections.Snacks,
        }
        for label, meal := range sections {
            if meal == nil {
                continue
            }
            b.WriteString(fmt.Sprintf("  %s: %s (%d kcal, P:%.0fg C:%.0fg F:%.0fg, $%.2f)\n",
                label, meal.RecipeName, int(meal.Macros.Calories),
                meal.Macros.ProteinG, meal.Macros.CarbsG, meal.Macros.FatG,
                float64(meal.EstimatedCostCents)/100))
        }
    }

    return b.String()
}
```

This would produce something like:

```
meal plan: 2026-05-28 → 2026-05-28

2026-05-28:
  Dinner: Beef and Eggplant Stir-fry with Brown Rice (1480 kcal, P:63g C:176g F:58g, $5.00)
```

